// CORS 白名单：只允许自己的站点调用，防止被第三方网站薅 API。
// 支持通配符匹配 *.vercel.app（Vercel 预览/生产域名）+ *.netlify.app（保留回退能力）。
const ALLOWED_ORIGIN_PATTERNS = [
  "https://medical-workflow-platform.netlify.app",
  "https://medical-workflow-platform.vercel.app",
  /^https:\/\/[a-z0-9-]+\.vercel\.app$/i,   // 任意 *.vercel.app 预览域名
  /^https:\/\/[a-z0-9-]+-[a-z0-9]+\.vercel\.app$/i, // 带 hash 的预览域名
  "http://localhost:5173",
  "http://localhost:4173",
]

function isAllowedOrigin(origin: string): boolean {
  return ALLOWED_ORIGIN_PATTERNS.some((p) =>
    typeof p === "string" ? p === origin : p.test(origin)
  )
}

// Vercel Node Runtime 标准 handler 签名（内联类型，避免依赖 @vercel/node）
type NodeReq = {
  method?: string
  headers: Record<string, string | string[] | undefined>
  body: unknown
}
type NodeRes = {
  setHeader: (k: string, v: string) => void
  status: (code: number) => NodeRes
  end: (data?: string) => void
}

function getOrigin(req: NodeReq): string {
  const h = req.headers
  const o = h["origin"] || h["Origin"]
  return Array.isArray(o) ? o[0] || "" : o || ""
}

function applyCors(req: NodeReq, res: NodeRes): string {
  const origin = getOrigin(req)
  const allowed = isAllowedOrigin(origin) ? origin : ALLOWED_ORIGIN_PATTERNS[0] as string
  res.setHeader("Access-Control-Allow-Origin", allowed)
  res.setHeader("Access-Control-Allow-Headers", "Content-Type, X-Access-Code")
  res.setHeader("Access-Control-Allow-Methods", "POST, OPTIONS")
  return allowed
}

function jsonError(req: NodeReq, res: NodeRes, status: number, body: unknown): void {
  applyCors(req, res)
  res.setHeader("Content-Type", "application/json; charset=utf-8")
  res.status(status).end(JSON.stringify(body))
}

// Vercel Hobby + Node Runtime 最长 60s（DeepSeek 官网 5-10s，绰绰有余）
export const config = {
  maxDuration: 60,
}

export default async (req: NodeReq, res: NodeRes): Promise<void> => {
  if (req.method === "OPTIONS") {
    applyCors(req, res)
    res.status(204).end()
    return
  }

  if (req.method !== "POST") {
    jsonError(req, res, 405, { error: "Method Not Allowed" })
    return
  }

  // ===== 访问口令校验 =====
  const accessCode = process.env.ACCESS_CODE
  if (accessCode) {
    const h = req.headers
    const raw = h["x-access-code"] || h["X-Access-Code"]
    const provided = Array.isArray(raw) ? raw[0] || "" : raw || ""
    if (provided !== accessCode) {
      jsonError(req, res, 401, { error: "未授权访问：口令错误或缺失" })
      return
    }
  }

  // ===== DeepSeek 官网 API 配置 =====
  const apiKey = process.env.DEEPSEEK_API_KEY
  if (!apiKey) {
    jsonError(req, res, 500, { error: "DEEPSEEK_API_KEY 环境变量未配置" })
    return
  }
  // 固定用 DeepSeek 官网：支持 JSON mode，返回严格 JSON，不会解析失败
  const apiBase = "https://api.deepseek.com/v1"
  const modelName = process.env.API_MODEL || "deepseek-chat"

  try {
    const body = (req.body || {}) as { topic?: string }
    const topic = body.topic?.trim()

    if (!topic) {
      jsonError(req, res, 400, { error: "缺少 topic 参数" })
      return
    }

    // 非流式：DeepSeek 官网 + JSON mode，5-10s 返回严格 JSON，无需流式容错
    const requestBody: Record<string, unknown> = {
      model: modelName,
      messages: [
        { role: "system", content: SYSTEM_PROMPT },
        { role: "user", content: topic },
      ],
      temperature: 0.3,
      response_format: { type: "json_object" },
    }

    const response = await fetch(`${apiBase}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${apiKey}`,
      },
      body: JSON.stringify(requestBody),
    })

    if (!response.ok) {
      const errorText = await response.text()
      jsonError(req, res, response.status, { error: `DeepSeek API 错误: ${errorText}` })
      return
    }

    const data = (await response.json()) as { choices?: Array<{ message?: { content?: string } }> }
    const content = data.choices?.[0]?.message?.content

    if (!content) {
      jsonError(req, res, 500, { error: "API 返回内容为空" })
      return
    }

    // DeepSeek 官网 + JSON mode 保证返回合法 JSON，直接校验后返回
    try {
      JSON.parse(content)
    } catch {
      jsonError(req, res, 500, { error: "AI 输出格式异常，请重试", raw: content.slice(0, 500) })
      return
    }

    applyCors(req, res)
    res.setHeader("Content-Type", "application/json; charset=utf-8")
    res.status(200).end(content)
  } catch (error) {
    jsonError(req, res, 500, {
      error: "服务器内部错误",
      message: error instanceof Error ? error.message : String(error),
    })
  }
}
